@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication by redirecting to IdP."""
    authn_request = sp.generate_authn_request()
    # For HTTP-Redirect binding
    redirect_url = (
        f"{SP_CONFIG['idp_sso_url']}?"
        f"SAMLRequest={authn_request}"
    )
    return redirect(redirect_url)


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - process SAML response from IdP."""
    saml_response = request.form.get('SAMLResponse')

    if not saml_response:
        abort(400, description="Missing SAMLResponse parameter")

    try:
        user_info = sp.process_response(saml_response)

        # Clear the SAML request ID from session
        session.pop('saml_request_id', None)

        # Create authenticated session
        session['authenticated'] = True
        session['user'] = {
            'id': user_info.get('name_id'),
            'email': user_info.get('email'),
            'first_name': user_info.get('first_name'),
            'last_name': user_info.get('last_name'),
            'groups': user_info.get('groups', []),
        }

        if 'session_index' in user_info:
            session['saml_session_index'] = user_info['session_index']

        # Regenerate session to prevent session fixation
        session.modified = True

        return redirect('/dashboard')

    except SAMLError as e:
        app.logger.error(f"SAML authentication failed: {e}")
        abort(403, description="Authentication failed")
    except Exception as e:
        app.logger.error(f"Unexpected error during SAML processing: {e}")
        abort(500, description="Internal server error")


@app.route('/saml/logout')
def saml_logout():
    """Log out the user and clear the session."""
    session.clear()
    return redirect('/')


@app.route('/dashboard')
def dashboard():
    """Protected resource - requires authentication."""
    if not session.get('authenticated'):
        return redirect('/saml/login')

    user = session.get('user', {})
    return f"Welcome, {user.get('first_name', 'User')}! Email: {user.get('email', 'N/A')}"


@app.route('/saml/metadata')
def saml_metadata():
    """Serve SP metadata for IdP configuration."""
    metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{SP_CONFIG['entity_id']}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="true"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SP_CONFIG['acs_url']}"
            index="0"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

    return metadata, 200, {'Content-Type': 'application/xml'}


